import{c as e,Q as a,j as n,m as t}from"./chunks/framework.D0LfRJ4P.js";const u=JSON.parse('{"title":"Cluster API (CAPI)","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/cluster-api.md","filePath":"showcases/cluster-api.md","lastUpdated":1775387067000}'),i={name:"showcases/cluster-api.md"};function l(r,s,o,c,p,d){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="cluster-api-capi" tabindex="-1">Cluster API (CAPI) <a class="header-anchor" href="#cluster-api-capi" aria-label="Permalink to &quot;Cluster API (CAPI)&quot;">​</a></h1><p>This showcase demonstrates <a href="https://cluster-api.sigs.k8s.io/" target="_blank" rel="noreferrer">Cluster API (CAPI)</a> — a Kubernetes sub-project that brings declarative, Kubernetes-style APIs to cluster lifecycle management. The standard k3d cluster acts as the <strong>management cluster</strong>, from which workload clusters are created and scaled via Kubernetes resources.</p><h3 id="about-this-demo" tabindex="-1">About this demo <a class="header-anchor" href="#about-this-demo" aria-label="Permalink to &quot;About this demo&quot;">​</a></h3><p>CAPI itself is fully <strong>platform agnostic</strong>. It supports infrastructure providers for AWS, Azure, GCP, vSphere, and many more. This demo uses the <strong>Docker infrastructure provider (CAPD)</strong>, which creates Kubernetes nodes as local Docker containers — making it ideal for local development and demos without any cloud account.</p><p>The infrastructure-specific parts (<code>DockerCluster</code>, <code>DockerMachineTemplate</code>) are the only pieces that change when targeting a different provider. The k3s control plane (<code>KThreesControlPlane</code>) and the bootstrap configuration remain identical across all providers.</p><h3 id="preconditions" tabindex="-1">Preconditions <a class="header-anchor" href="#preconditions" aria-label="Permalink to &quot;Preconditions&quot;">​</a></h3><ul><li>The k3d management cluster must be created with <strong>CAPI support enabled</strong> (answer <code>Yes</code> to <em>&quot;Enable Cluster API (CAPI) support?&quot;</em> in <code>create-sample.sh</code>). This mounts the Docker socket into the k3d server and agent nodes, which CAPD requires to create workload cluster nodes as Docker containers.</li><li><a href="https://cluster-api.sigs.k8s.io/user/quick-start.html#install-clusterctl" target="_blank" rel="noreferrer"><code>clusterctl</code></a> must be installed on your host:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clusterctl</span></span></code></pre></div><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cluster-api</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>The script will:</p><ol><li>Configure <code>clusterctl</code> to use the k3s bootstrap and control-plane providers</li><li>Initialize CAPI on the management cluster (core, k3s bootstrap, k3s control-plane, Docker infrastructure)</li><li>Remove the httpbin sample from the management cluster</li><li>Create a workload cluster with 1 control plane node and 1 worker node (via Cluster API)</li><li>Connect the workload cluster containers to the management cluster&#39;s Docker network</li><li>Deploy httpbin on the workload cluster and expose it through the management cluster&#39;s HAProxy ingress</li></ol><h3 id="accessing-httpbin" tabindex="-1">Accessing httpbin <a class="header-anchor" href="#accessing-httpbin" aria-label="Permalink to &quot;Accessing httpbin&quot;">​</a></h3><p>Once setup is complete, httpbin running in the workload cluster is accessible via the management cluster&#39;s load balancer:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127-0-0-1.nip.io:8080</span></span></code></pre></div><p>To interact with the workload cluster directly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KUBECONFIG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">examples/cluster-api/workload-kubeconfig.yaml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> po</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span></span></code></pre></div><h3 id="scaling-workers" tabindex="-1">Scaling workers <a class="header-anchor" href="#scaling-workers" aria-label="Permalink to &quot;Scaling workers&quot;">​</a></h3><p>Add or remove worker nodes interactively:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cluster-api</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale-workers.sh</span></span></code></pre></div><p>The script shows the current number of worker replicas and prompts for the desired count:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Using management cluster context: k3d-demo</span></span>
<span class="line"><span>Tip: CAPI resources always live on the management cluster, regardless of your current kubeconfig/context.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Current worker replicas: 1</span></span>
<span class="line"><span>Desired number of workers [1]: 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Scaling worker nodes to 3</span></span>
<span class="line"><span>-------------------------------------</span></span>
<span class="line"><span>machinedeployment.cluster.x-k8s.io/workload-cluster-md-0 scaled</span></span>
<span class="line"><span>Waiting for 3 machines to be ready...</span></span>
<span class="line"><span>  Connected workload-cluster-md-0-...-xxxxx to k3d-demo</span></span>
<span class="line"><span>  Removed cloud-provider taint from workload-cluster-md-0-...-xxxxx</span></span>
<span class="line"><span>  Ready: 2/3 — waiting...</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>NAME                              STATUS   ROLES                       AGE   VERSION</span></span>
<span class="line"><span>workload-cluster-kcp-*            Ready    control-plane,etcd,master   ...   v1.30.2+k3s2</span></span>
<span class="line"><span>workload-cluster-md-0-*           Ready    &lt;none&gt;                      ...   v1.30.2+k3s2</span></span>
<span class="line"><span>workload-cluster-md-0-*           Ready    &lt;none&gt;                      ...   v1.30.2+k3s2</span></span>
<span class="line"><span>workload-cluster-md-0-*           Ready    &lt;none&gt;                      ...   v1.30.2+k3s2</span></span></code></pre></div><p>CAPI reconciles the <code>MachineDeployment</code> to the desired replica count by provisioning or deleting Docker containers. Scaling down removes worker nodes gracefully.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Always run <code>scale-workers.sh</code> from the <code>examples/cluster-api/</code> directory, and regardless of which <code>KUBECONFIG</code> is currently active in your shell — the script always targets the management cluster context (<code>k3d-demo</code>).</p></div><h3 id="teardown" tabindex="-1">Teardown <a class="header-anchor" href="#teardown" aria-label="Permalink to &quot;Teardown&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/cluster-api</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> teardown.sh</span></span></code></pre></div><p>This will:</p><ol><li>Delete the workload cluster via CAPI (all Docker containers for CP and workers are removed)</li><li>Wait for full deletion</li><li>Remove the local <code>workload-kubeconfig.yaml</code></li><li>Re-deploy httpbin on the management cluster</li></ol><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host machine</span></span>
<span class="line"><span>└── Docker</span></span>
<span class="line"><span>    ├── k3d management cluster (k3d-demo)   ← CAPI controllers run here</span></span>
<span class="line"><span>    │   └── HAProxy Ingress → Endpoints → workload cluster worker</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── Workload cluster (CAPD / Docker)</span></span>
<span class="line"><span>        ├── workload-cluster-lb              ← HAProxy LB for API server</span></span>
<span class="line"><span>        ├── workload-cluster-kcp-*           ← k3s control plane node</span></span>
<span class="line"><span>        └── workload-cluster-md-*            ← k3s worker node (httpbin)</span></span></code></pre></div><p>Both cluster sets share the <code>k3d-demo</code> Docker network, enabling the management cluster&#39;s HAProxy to route HTTP traffic directly to the workload cluster worker&#39;s NodePort.</p><div class="warning custom-block"><p class="custom-block-title">Docker requirement</p><p>CAPD requires access to the Docker socket to create and manage workload cluster nodes as containers. This is handled automatically when CAPI support is enabled in <code>create-sample.sh</code>. Switching to a cloud provider (e.g. AWS, Azure) would remove this requirement entirely — only the infrastructure manifests (<code>DockerCluster</code> → <code>AWSCluster</code>, etc.) would need to change.</p></div>`,32)])])}const k=e(i,[["render",l]]);export{u as __pageData,k as default};
